50	void LLVMCPUTilePass::runOnOperation() {
51	  if (tilingLevel == -1) {
52	    LLVM_DEBUG(llvm::dbgs() << "tilingLevel not set, skip tiling\n");
53	    return;
54	  }
55	  MLIRContext *context = &getContext();
56	  auto funcOp = getOperation();
57	
58	  SmallVector<Operation *> computeOps = getComputeOps(funcOp);
59	  FailureOr<IREE::Codegen::LoweringConfigAttr> rootLoweringConfig =
60	      getFirstLoweringConfig<IREE::Codegen::LoweringConfigAttr>(computeOps);
61	  if (failed(rootLoweringConfig)) {
62	    LLVM_DEBUG(llvm::dbgs() << "can't find lowering_config, skip tiling\n");
63	    return;
64	  }
65	
66	  for (auto computeOp : computeOps) {
67	    auto op = dyn_cast<TilingInterface>(computeOp);
68	    if (!op || op.getLoopIteratorTypes().empty())
69	      continue;
70	
71	    // For now do not tile `tensor.pad` operations. The `tensor.pad`
72	    // operations might be those introduced by the padding-based
73	    // codegeneration strategy. Those are not meant to be tiled again.
74	    // Need a better way for handling this, but this works for now.
75	    if (isa<tensor::PadOp>(computeOp))
76	      continue;
77	
78	    LLVM_DEBUG(llvm::dbgs() << "candidate: " << op << "\n");
79	    SmallVector<int64_t> tileSizes;
80	    SmallVector<bool> tileScalableFlags;
81	    if (auto loweringConfig =
82	            getLoweringConfig<IREE::Codegen::LoweringConfigAttr>(op)) {
83	      tileSizes = loweringConfig.getTileSizeVals(tilingLevel);
84	      tileScalableFlags = loweringConfig.getScalableTileFlagVals(tilingLevel);
85	    } else {
86	      tileSizes = rootLoweringConfig.value().getTileSizeVals(tilingLevel);
87	      tileScalableFlags =
88	          rootLoweringConfig.value().getScalableTileFlagVals(tilingLevel);
89	    }
90	
91	    if (llvm::all_of(tileSizes, [](int64_t v) { return v == 0; })) {
92	      LLVM_DEBUG(llvm::dbgs() << "tiling sizes are all zeros, skip tiling\n");
93	      continue;
94	    }
95	
96	    IRRewriter rewriter(context);
97	    scf::SCFTilingOptions options{};
98	    setSCFTileSizes(options, op, std::move(tileSizes),
99	                    std::move(tileScalableFlags));
100	    FailureOr<scf::SCFTilingResult> tiledResults =
101	        scf::tileUsingSCF(rewriter, op, options);
102	    if (failed(tiledResults))
103	      continue;
104	    rewriter.replaceOp(op, tiledResults->mergeResult.replacements);
105	  }
106	
107	  RewritePatternSet patterns =
108	      linalg::getLinalgTilingCanonicalizationPatterns(context);
109	  scf::populateSCFForLoopCanonicalizationPatterns(patterns);
110	  tensor::populateFoldTensorEmptyPatterns(patterns);
111	  memref::populateResolveRankedShapedTypeResultDimsPatterns(patterns);
112	  context->getLoadedDialect<tensor::TensorDialect>()
113	      ->getCanonicalizationPatterns(patterns);
114	  if (failed(applyPatternsGreedily(funcOp, std::move(patterns)))) {
115	    LLVM_DEBUG(llvm::dbgs() << "----- cleanup failed -----\n");
116	    return signalPassFailure();
117	  }
118	}
119	} // namespace
