34	/// Starting from `op` walk all operands backwards to find all
35	/// potentially fusable operations, i.e. operations that implement
36	/// the `TilingInterface`.
37	static void collectTiledAndFusedOps(Operation *rootOp,
38	                                    llvm::SmallDenseSet<Operation *> &result) {
39	  SmallVector<Operation *> worklist;
40	  worklist.push_back(rootOp);
41	  result.insert(rootOp);
42	  while (!worklist.empty()) {
43	    Operation *current = worklist.pop_back_val();
44	    for (OpOperand &operand : current->getOpOperands()) {
45	      Operation *producer = operand.get().getDefiningOp();
46	      if (!producer || !isa<TilingInterface>(producer) ||
47	          result.count(producer))
48	        continue;
49	      worklist.push_back(producer);
50	      result.insert(producer);
51	    }
52	  }
53	}
