55	/// Tiling of `tensor.pad` operation generates
56	///
57	/// ```mlir
58	/// scf.if {
59	///   ...
60	/// } else {
61	///    tensor.pad
62	/// }
63	/// ```
64	///
65	/// For IREEs use case we dont need this. So this folds away the `if` condition.
66	/// Note this is a fairly hacky workaround, but the current pad operation
67	/// semantics force us down this path.
68	static FailureOr<tensor::PadOp>
69	foldIfGeneratedFromPadding(RewriterBase &rewriter, tensor::PadOp untiledPadOp,
70	                           tensor::PadOp tiledPadOp) {
71	  auto ifOp = dyn_cast<scf::IfOp>(tiledPadOp->getParentOp());
72	  if (!ifOp) {
73	    return failure();
74	  };
75	  Block *block = tiledPadOp->getBlock();
76	  Operation *terminator = block->getTerminator();
77	  ValueRange results = terminator->getOperands();
78	  rewriter.inlineBlockBefore(block, ifOp, /*blockArgs=*/{});
79	  rewriter.replaceOp(ifOp, results);
80	  rewriter.eraseOp(terminator);
81	  return tiledPadOp;
82	}
