107	  collectTiledAndFusedOps(rootOp, origTiledAndFusedOps);
108	  auto isIgnoredUser = [&](Operation *user,
109	                           LoopLikeOpInterface outerMostTiledLoop) {
110	    return origTiledAndFusedOps.count(user) ||
111	           isa<tensor::DimOp, IREE::Codegen::UKernelGenericOp>(user);
112	  };
113	
114	  // The rest of this method is similar to
115	  // scf::tileConsumerAndFuseProducerGreedilyUsingSCFForOp, except that this
116	  // replaces DPS out operand with iter_arg when they use the same init
117	  // operands.
118	
119	  // 1. Tile the consumer.
120	  SmallVector<OpResult> yieldedValuesToOrigValues;
121	  SmallVector<Operation *> tiledOps;
122	  FailureOr<scf::SCFTilingResult> tilingResult =
123	      scf::tileUsingSCF(rewriter, cast<TilingInterface>(rootOp), options);
124	  if (failed(tilingResult)) {
