138	        rewriter, rootPadOp, cast<tensor::PadOp>(tilingResult->tiledOps[0]));
139	    if (!failed(replacementTiledOp)) {
140	      tilingResult->tiledOps[0] = replacementTiledOp.value();
141	    }
142	  } else if (auto dpsOp = dyn_cast<DestinationStyleOpInterface>(rootOp)) {
