57	  // Empty if no affinities were specified.
58	  SetVector<IREE::Stream::AffinityAttr> affinities;
59	  // Workload used as input to the workgroup count calculation function.
60	  SmallVector<unsigned> workload;
61	  // Analyzed minimum binding sizes.
