70	// Walk |moduleOp| and gather all of the dispatches to each executable.
71	// Dispatch parameters are deduplicated by workload so that there's only ever
72	// one entry for all dispatches with a given workgroup count.
73	// Dispatches will be ignored if they have a dynamic workload or any dynamically
74	// sized resources.
75	static DispatchParamsMap gatherDispatchParams(mlir::ModuleOp moduleOp,
76	                                              SymbolTable &symbolTable) {
77	  DispatchParamsMap map;
78	
79	  for (auto funcOp : moduleOp.getOps<mlir::FunctionOpInterface>()) {
80	    funcOp.walk([&](IREE::Stream::CmdDispatchOp dispatchOp) {
81	      auto affinityAttr = dyn_cast_if_present<IREE::HAL::DeviceAffinityAttr>(
82	          IREE::Stream::AffinityAttr::lookup(dispatchOp));
83	      if (!affinityAttr) {
84	        LLVM_DEBUG(
85	            llvm::dbgs()
86	            << "skipping dispatch because it has no affinity specified\n");
87	        return;
88	      }
89	
90	      auto workloadValues = dispatchOp.getWorkload();
91	      SmallVector<unsigned> workload;
92	      workload.reserve(workloadValues.size());
93	      for (auto workloadValue : workloadValues) {
94	        APInt workloadConstValue;
95	        if (!matchPattern(workloadValue, m_ConstantInt(&workloadConstValue))) {
96	          LLVM_DEBUG({
97	            auto firstEntryPoint = *dispatchOp.getEntryPointRefs().begin();
98	            llvm::dbgs() << "skipping dispatch of entry point `"
99	                         << firstEntryPoint << "` (non-constant workload)\n";
100	          });
101	          return;
102	        }
103	        workload.push_back(workloadConstValue.getSExtValue());
104	      }
105	
106	      SmallVector<TypedAttr> uniformOperands;
107	      for (auto operand : dispatchOp.getUniformOperands()) {
108	        TypedAttr uniformOperand;
109	        if (!matchPattern(operand, m_Constant(&uniformOperand))) {
110	          // TODO(benvanik): extract information from the executable annotations
111	          // or allow the dynamic value to be passed in as an additional arg.
112	          LLVM_DEBUG({
113	            auto firstEntryPoint = *dispatchOp.getEntryPointRefs().begin();
114	            llvm::dbgs() << "Skipping dispatch of entry point `"
115	                         << firstEntryPoint
116	                         << "` (non-constant uniform operand)\n";
117	          });
118	          return;
119	        }
120	        uniformOperands.push_back(uniformOperand);
121	      }
122	
123	      // Work around needing a mutable key for the set; C++ was a mistake.
124	      dispatchOp.forEachEntryPointAttr([&](SymbolRefAttr entryPointAttr) {
125	        SmallVector<Binding> bindings;
126	        for (auto [i, resourceLength] :
127	             llvm::enumerate(dispatchOp.getResourceLengths())) {
128	          APInt resourceLengthInt;
129	          if (!matchPattern(resourceLength,
130	                            m_ConstantInt(&resourceLengthInt))) {
131	            LLVM_DEBUG(llvm::dbgs() << "skipping dispatch of entry point `"
132	                                    << entryPointAttr
133	                                    << "` (non-constant resource length)\n";);
134	            return;
135	          }
136	          bindings.push_back({(unsigned)i, resourceLengthInt.getSExtValue()});
137	        }
138	
139	        auto &dispatchParamsSet = map[entryPointAttr];
140	        DispatchParams *dispatchParams = nullptr;
141	        for (auto &it : dispatchParamsSet) {
142	          if (it.workload == workload) {
143	            dispatchParams = &it;
144	            break;
145	          }
146	        }
147	        if (!dispatchParams) {
148	          dispatchParamsSet.push_back({});
149	          dispatchParams = &dispatchParamsSet.back();
150	        }
151	        dispatchParams->locs.push_back(dispatchOp.getLoc());
152	        dispatchParams->affinities.insert(affinityAttr);
153	        dispatchParams->workload = workload;
154	        dispatchParams->bindings = std::move(bindings);
155	        dispatchParams->uniformOperands = std::move(uniformOperands);
156	      });
157	    });
158	  }
159	
160	  return map;
161	}
