35	/// Starting from `op` walk all operands backwards to find all
36	/// potentially fusable operations, i.e. operations that implement
37	/// the `TilingInterface`.
38	static void collectTiledAndFusedOps(Operation *rootOp,
39	                                    llvm::SmallDenseSet<Operation *> &result) {
40	  SmallVector<Operation *> worklist;
41	  worklist.push_back(rootOp);
42	  result.insert(rootOp);
43	  while (!worklist.empty()) {
44	    Operation *current = worklist.pop_back_val();
45	    for (OpOperand &operand : current->getOpOperands()) {
46	      Operation *producer = operand.get().getDefiningOp();
47	      if (!producer || !isa<TilingInterface>(producer) ||
48	          result.count(producer))
49	        continue;
50	      worklist.push_back(producer);
51	      result.insert(producer);
52	    }
53	  }
54	}
