56	/// Tile the root operation and fuse the producers of the root operation.
57	/// If `onlyFuseProducerInputOperands` is set, only fuse producer input
58	/// operands. Returns the tiled operation to be used for fusing consumers.
59	FailureOr<Operation *>
60	tileRootAndFuseProducers(IRRewriter &rewriter, TilingInterface rootOp,
61	                         int64_t tilingLevel,
62	                         bool onlyFuseProducerInputOperands) {
63	  mlir::DominanceInfo dominanceInfo(rootOp);
64	  llvm::SmallDenseSet<Operation *> tiledAndFusedOps;
65	  collectTiledAndFusedOps(rootOp, tiledAndFusedOps);
66	
67	  llvm::DenseSet<Operation *> yieldReplacementsFor;
68	  for (auto op : tiledAndFusedOps) {
69	    if (llvm::any_of(op->getUsers(), [&](Operation *user) {
70	          return dominanceInfo.properlyDominates(rootOp, user);
71	        })) {
72	      yieldReplacementsFor.insert(op);
73	    }
74	  }
75	
76	  SmallVector<OpFoldResult> tileSizes =
77	      getLoweringConfig(rootOp).getTilingLevelSizes(rewriter, tilingLevel,
78	                                                    rootOp);
79	
80	  // Pad the tile sizes with zero.
81	  auto zero = rewriter.getIndexAttr(0);
82	  int64_t numLoops = rootOp.getLoopIteratorTypes().size();
83	  if (tileSizes.size() > numLoops) {
84	    LLVM_DEBUG(llvm::dbgs()
85	               << "tile sizes size " << tileSizes.size()
86	               << " exceeds the number of loops " << numLoops << "\n");
87	    return failure();
88	  }
89	  tileSizes.resize(numLoops, zero);
90	
91	  scf::SCFTilingOptions tilingOptions;
92	  tilingOptions.setTileSizes(tileSizes);
93	
94	  scf::SCFTileAndFuseOptions tileAndFuseOptions;
95	  tileAndFuseOptions.setTilingOptions(tilingOptions);
96	
97	  scf::SCFTileAndFuseOptions::ControlFnTy controlFn =
98	      [&](tensor::ExtractSliceOp candidateSliceOp, OpResult originalProducer,
99	          bool isDestinationOperand)
100	      -> std::optional<scf::SCFTileAndFuseOptions::ControlFnResult> {
101	    Operation *owner = originalProducer.getOwner();
102	    bool yieldProducerReplacement = yieldReplacementsFor.contains(owner);
103	    // Do not fuse destination operands if onlyFuseProducerInputOperands is
104	    // true.
105	    bool shouldFuse = !(onlyFuseProducerInputOperands && isDestinationOperand);
106	    if (shouldFuse) {
107	      return scf::SCFTileAndFuseOptions::ControlFnResult{
108	          yieldProducerReplacement};
109	    }
110	    return std::nullopt;
111	  };
112	  tileAndFuseOptions.setFusionControlFn(controlFn);
113	
114	  FailureOr<scf::SCFTileAndFuseResult> tiledResults =
115	      scf::tileConsumerAndFuseProducersUsingSCF(rewriter, rootOp,
116	                                                tileAndFuseOptions);
117	  if (failed(tiledResults)) {
118	    return failure();
119	  }
120	
121	  // Perform the replacement of tiled and fused values.
122	  SmallVector<Operation *> opsToReplace{rootOp};
123	  llvm::append_range(opsToReplace, tiledResults->fusedProducers);
124	  for (Operation *toReplace : opsToReplace) {
125	    for (OpResult res : toReplace->getResults())
126	      if (auto replacement = tiledResults->replacements.lookup(res)) {
127	        Operation *replacementOp = replacement.getDefiningOp();
128	        rewriter.replaceUsesWithIf(res, replacement, [&](OpOperand &use) {
129	          Operation *user = use.getOwner();
130	          return dominanceInfo.properlyDominates(replacementOp, user);
131	        });
132	      }
133	
134	    if (toReplace->use_empty()) {
135	      rewriter.eraseOp(toReplace);
136	    }
137	  }
138	
139	  return tiledResults->tiledAndFusedOps.front();
140	}
