142	static void fuseConsumers(RewriterBase &rewriter, Operation *tiledOp) {
143	
144	  //  Typically, the consumers of the tiled operation are slices of the
145	  //  results of the tiled operation. These are expressed in IR using
146	  //  `tensor.insert_slice` operations, whose outputs are the operands of the
147	  //  untiled operation. Create a worklist of these `tensor.insert_siices`
148	  //  operations. If the consumers of the source of the `tensor.insert_slices`
149	  //  can be tiled such that the tiled value is generated in-place, that
150	  //  effectively tiles + fuses the operations.
151	  auto addCandidateSlices = [](Operation *fusedOp,
152	                               std::queue<tensor::InsertSliceOp> &candidates) {
153	    for (auto *userOp : fusedOp->getResults().getUsers()) {
154	      if (auto sliceOp = llvm::dyn_cast<tensor::InsertSliceOp>(userOp)) {
155	        candidates.push(sliceOp);
156	      }
157	    }
158	  };
159	
160	  // Collect the candidate slices which can be potential consumers that can be
161	  // fused.
162	  std::queue<tensor::InsertSliceOp> candidates;
163	  addCandidateSlices(tiledOp, candidates);
164	
165	  while (!candidates.empty()) {
166	
167	    // Traverse the slices in BFS fashion.
168	    tensor::InsertSliceOp candidateSliceOp = candidates.front();
169	    candidates.pop();
170	
171	    FailureOr<scf::SCFFuseConsumerOfSliceResult> fusedResult =
172	        mlir::scf::tileAndFuseConsumerOfSlice(rewriter, candidateSliceOp);
173	    if (failed(fusedResult)) {
174	      LLVM_DEBUG(llvm::dbgs() << "failed to fuse consumer of slice: "
175	                              << candidateSliceOp << "\n");
